```python
# checkers.py

class Board:
    def __init__(self):
        self.board = [
            [None, 'B', None, 'B', None, 'B', None, 'B'],
            ['B', None, 'B', None, 'B', None, 'B', None],
            [None, 'B', None, 'B', None, 'B', None, 'B'],
            [None, None, None, None, None, None, None, None],
            [None, None, None, None, None, None, None, None],
            ['W', None, 'W', None, 'W', None, 'W', None],
            [None, 'W', None, 'W', None, 'W', None, 'W'],
            [None, None, None, None, None, None, None, None]
        ]
        self.turn = 'B'

    def print_board(self):
        for row in self.board:
            print(' '.join([f' {x} ' if x else '|   |' for x in row]))
            print('---|---|---|---|---|---|---')

    def get_piece(self, row, col):
        return self.board[row][col]

    def move(self, start_row, start_col, end_row, end_col):
        piece = self.get_piece(start_row, start_col)
        if piece and (self.turn == 'B' and piece == 'b') or (self.turn == 'W' and piece == 'w'):
            self.board[start_row][start_col] = None
            if abs(end_row - start_row) == 2:
                self.remove_piece((end_row + start_row) // 2, (end_col + start_col) // 2)
            self.board[end_row][end_col] = piece.upper() if end_row == 0 or end_row == 7 else piece
            self.turn = 'W' if self.turn == 'B' else 'B'

    def remove_piece(self, row, col):
        self.board[row][col] = None

    def is_valid_move(self, start_row, start_col, end_row, end_col):
        piece = self.get_piece(start_row, start_col)
        if not piece or (self.turn == 'B' and piece == 'w') or (self.turn == 'W' and piece == 'b'):
            return False
        if end_row < 0 or end_row > 7 or end_col < 0 or end_col > 7:
            return False
        if abs(end_row - start_row) != 1 and abs(end_row - start_row) != 2:
            return False
        if end_col == start_col:
            return False
        if self.get_piece(end_row, end_col):
            return False
        if abs(end_col - start_col) == 2 and not (self.get_piece((end_row + start_row) // 2, (end_col + start_col) // 2)):
            return False
        return True

    def has_valid_moves(self):
        for row in range(8):
            for col in range(8):
                piece = self.get_piece(row, col)
                if piece and ((self.turn == 'B' and piece.lower() == 'b') or (self.turn == 'W' and piece.lower() == 'w')):
                    for dr, dc in [(-1, -1), (-1, 1), (1, -1), (1, 1)]:
                        if self.is_valid_move(row, col, row + 2 * dr, col + 2 * dc):
                            return True
        return False

class CheckersGame:
    def __init__(self):
        self.board = Board()

    def play(self):
        while self.board.has_valid_moves():
            self.board.print_board()
            move = input(f"Player {self.board.turn}, enter your move (e.g., 2,1 to 4,3): ")
            start_row, start_col, end_row, end_col = map(int, move.split(','))
            if self.board.is_valid_move(start_row, start_col, end_row, end_col):
                self.board.move(start_row, start_col, end_row, end_col)
            else:
                print("Invalid move. Try again.")
        self.board.print_board()
        winner = 'W' if self.board.turn == 'B' else 'B'
        print(f"Player {winner} wins!")

# Main function to run the game
if __name__ == "__main__":
    game = CheckersGame()
    game.play()
```

### Explanation:
1. **Board Class**:
   - Initializes an 8x8 board with alternating black (`b`) and white (`w`) pieces.
   - Prints the current state of the board.
   - Retrieves a piece from a specific position on the board.
   - Moves a piece from one position to another, handling captures and kinging.
   - Removes a piece from the board.
   - Checks if a move is valid based on the game rules.
   - Checks if there are any valid moves left for the current player.

2. **CheckersGame Class**:
   - Initializes the game with a new `Board` object.
   - Main loop to play the game, alternating turns between players.
   - Prompts each player to enter their move in notation (e.g., 2,1 to 4,3).
   - Checks if the move is valid and updates the board accordingly.
   - Prints the final state of the board and declares the winner.

